import React, { useState, useEffect, useCallback } from 'react';
import { Container, Card, Form, Button, Row, Col, Alert, Table } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const ML_PER_GLASS = 250;

const WaterLog = () => {
  const { token, authFetch } = useAuth();
  const navigate = useNavigate();
  const [glasses, setGlasses] = useState('1');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [summary, setSummary] = useState(null);

  const loadToday = useCallback(async () => {
    const res = await authFetch('/api/water');
    if (res.status === 401) {
      navigate('/login');
      return;
    }
    const data = await res.json();
    if (!res.ok) {
      setError(data.error || 'Failed to load water log');
      return;
    }
    setSummary(data);
  }, [authFetch, navigate]);

  useEffect(() => {
    if (!token) {
      navigate('/login');
      return;
    }
    loadToday();
  }, [token, navigate, loadToday]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const g = parseInt(glasses, 10);
      if (!g || g < 1) {
        setError('Enter at least 1 glass');
        setLoading(false);
        return;
      }
      const res = await authFetch('/api/water', {
        method: 'POST',
        body: { glasses: g },
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.error || 'Could not log water');
        return;
      }
      setGlasses('1');
      await loadToday();
    } catch {
      setError('Network error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container className="py-4">
      <h2 className="mb-4">Log water intake</h2>
      <Row>
        <Col md={5}>
          <Card className="mb-4">
            <Card.Body>
              <Card.Title>Add water</Card.Title>
              {error && <Alert variant="danger">{error}</Alert>}
              <Form onSubmit={handleSubmit}>
                <Form.Group className="mb-3">
                  <Form.Label>Glasses ({ML_PER_GLASS} ml each)</Form.Label>
                  <Form.Control
                    type="number"
                    min="1"
                    value={glasses}
                    onChange={(e) => setGlasses(e.target.value)}
                  />
                </Form.Group>
                <Button type="submit" disabled={loading}>
                  {loading ? 'Saving…' : 'Log water'}
                </Button>
              </Form>
            </Card.Body>
          </Card>
        </Col>
        <Col md={7}>
          <Card>
            <Card.Body>
              <Card.Title>Today {summary ? `(${summary.date})` : ''}</Card.Title>
              {summary && (
                <>
                  <p className="lead mb-2">
                    {summary.total_ml} ml total (~{summary.total_glasses} glasses)
                  </p>
                  <Table size="sm" responsive>
                    <thead>
                      <tr>
                        <th>Time (UTC)</th>
                        <th>Amount</th>
                      </tr>
                    </thead>
                    <tbody>
                      {summary.logs.length === 0 ? (
                        <tr>
                          <td colSpan={2} className="text-muted">
                            No entries yet
                          </td>
                        </tr>
                      ) : (
                        summary.logs.map((log) => (
                          <tr key={log.id}>
                            <td>{new Date(log.logged_at).toLocaleString()}</td>
                            <td>{log.amount_ml} ml</td>
                          </tr>
                        ))
                      )}
                    </tbody>
                  </Table>
                </>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
};

export default WaterLog;
